const processedItems = [];

for (const item of $input.all()) {
  const rawText = item.json.content[0].text;

  // 1. Làm sạch Markdown (xóa ```json và ```) trước khi Parse
  const cleanText = rawText.replace(/```json|```/g, "").trim();

  try {
    const data = JSON.parse(cleanText);

    // 2. Chỉ lấy những item là dự án thực sự
    if (data.is_project === true) {

      // 3. Chuẩn hóa dữ liệu để khớp với projects.json của bạn
      const formattedData = {
        id: Math.floor(Date.now() / 1000) + Math.floor(Math.random() * 1000), // Tạo ID ngẫu nhiên
        name: data.name,
        investor: data.investor,
        district: data.district,
        provinceId: data.province?.toLowerCase()
                        .normalize("NFD")
                        .replace(/[\u0300-\u036f]/g, "")
                        .replace(/\s+/g, '') || "unknown",
        province: data.province,
        price: data.price > 1000000 ? Math.round(data.price / 1000000) : data.price, // Đổi từ 31.400.000 về 31 triệu nếu cần
        minArea: data.minArea,
        maxArea: data.maxArea,
        totalUnits: data.totalUnits,
        status: data.status,
        statusType: "open",
        notes: data.notes,
        updatedAt: new Date().toISOString()
      };

      processedItems.push({ json: formattedData });
    }
  } catch (error) {
    // Nếu có lỗi parse JSON ở 1 item, bỏ qua và chạy tiếp item sau
    console.error("Lỗi parse JSON tại item:", error);
  }
}

// 4. Trả về toàn bộ danh sách dự án đã lọc sạch
return processedItems;

// 1. Lấy dữ liệu mới trực tiếp từ đầu vào của node này
const newProjects = $input.all().map(item => item.json);

// 2. Lấy dữ liệu cũ từ node GitHub Get
// CỰC KỲ QUAN TRỌNG: 'GitHub Get' phải khớp y hệt tên node trên màn hình của bạn
const githubData = $('GitHub Get').item.json; 
const oldContentBase64 = githubData.content;
const fileSha = githubData.sha; 

let existingProjects = [];

try {
    // Giải mã Base64 sang JSON
    const decodedString = Buffer.from(oldContentBase64, 'base64').toString('utf-8');
    existingProjects = JSON.parse(decodedString);
} catch (e) {
    // Nếu file trống hoặc lỗi, bắt đầu với mảng rỗng
    existingProjects = [];
}

// 3. Gộp và lọc trùng theo tên dự án
const merged = [...newProjects];

existingProjects.forEach(oldP => {
    // Chỉ thêm lại dự án cũ nếu tên chưa có trong danh sách mới
    const isDuplicate = merged.some(newP => newP.name === oldP.name);
    if (!isDuplicate) {
        merged.push(oldP);
    }
});

// 4. Sắp xếp lại: Tin mới nhất lên đầu
merged.sort((a, b) => new Date(b.updatedAt) - new Date(a.updatedAt));

// 5. Trả về kết quả cuối kèm SHA cho node GitHub Edit
return {
    final_content: JSON.stringify(merged, null, 2),
    sha: fileSha
};
